     1→import { z } from 'zod';
     2→import { EmailMessage, HardAssertionResult } from '../types';
     3→
     4→/**
     5→ * Hard Assertions Stage
     6→ *
     7→ * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md "Hard Assertions" section.
     8→ * Single match can directly elevate a top-level category to high confidence baseline.
     9→ *
    10→ * Logic:
    11→ * - If any hard assertion matches: category_score = max(category_score, HIGH_CONFIDENCE_FLOOR)
    12→ * - Mark flag: hard_assertion = true
    13→ * - Where HIGH_CONFIDENCE_FLOOR = confidence_thresholds.high_confidence
    14→ */
    15→
    16→export interface ClassificationContext {
    17→  emailId: string;
    18→  sessionId: string;
    19→  categoryScores: Record<string, number>;
    20→  hardAssertionsApplied: string[];
    21→  stageTimings: Record<string, number>;
    22→  configurationRefs: Record<string, string>;
    23→}
    24→
    25→export interface HardAssertionConfig {
    26→  from_domains_ref?: {
    27→    source_group: string;
    28→    confidence: 'high' | 'medium';
    29→  };
    30→  subject_prefixes?: string[];
    31→  from_addresses?: string[];
    32→}
    33→
    34→export interface HardAssertionStageConfig {
    35→  confidenceThresholds: {
    36→    high_confidence: number;
    37→    medium_confidence: number;
    38→    low_confidence: number;
    39→  };
    40→  categorySignals: Record<string, { hard_assertions?: HardAssertionConfig }>;
    41→  domainLookup: Record<
    42→    string,
    43→    {
    44→      high_confidence: Array<{ domain: string; type?: string }>;
    45→      medium_confidence: Array<{ domain: string; type?: string }>;
    46→      low_confidence: Array<{ domain: string; type?: string }>;
    47→    }
    48→  >;
    49→}
    50→
    51→export interface HardAssertionStageResult {
    52→  categoriesWithHardAssertions: string[];
    53→  assertionResults: HardAssertionResult[];
    54→  updatedScores: Record<string, number>;
    55→  processingDurationMs: number;
    56→}
    57→
    58→/**
    59→ * Executes hard assertions stage of email classification
    60→ *
    61→ * @param email The email message to classify
    62→ * @param context Current classification context with category scores
    63→ * @param config Configuration containing category signals and thresholds
    64→ * @returns Hard assertion results and updated scores
    65→ */
    66→export function executeHardAssertions(
    67→  email: EmailMessage,
    68→  context: ClassificationContext,
    69→  config: HardAssertionStageConfig
    70→): HardAssertionStageResult {
    71→  const startTime = Date.now();
    72→  const categoriesWithHardAssertions: string[] = [];
    73→  const assertionResults: HardAssertionResult[] = [];
    74→  const updatedScores: Record<string, number> = { ...context.categoryScores };
    75→
    76→  const HIGH_CONFIDENCE_FLOOR = config.confidenceThresholds.high_confidence;
    77→
    78→  // Process each category that has hard assertions configured
    79→  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    80→    if (!categoryConfig.hard_assertions) {
    81→      continue;
    82→    }
    83→
    84→    const hardAssertions = categoryConfig.hard_assertions;
    85→    let categoryHadAssertion = false;
    86→
    87→    // Check from_domains_ref (domain-based hard assertions)
    88→    if (hardAssertions.from_domains_ref) {
    89→      const { source_group, confidence } = hardAssertions.from_domains_ref;
    90→
    91→      // Only treat as hard assertion if confidence is 'high'
    92→      if (confidence === 'high') {
    93→        const domainGroup = config.domainLookup[source_group];
    94→        if (domainGroup) {
    95→          const emailDomain = extractDomainFromEmail(email.from.email);
    96→          const matchedDomain = domainGroup.high_confidence.find((d) => domainMatches(emailDomain, d.domain));
    97→
    98→          if (matchedDomain) {
    99→            assertionResults.push({
   100→              category: categoryName,
   101→              triggered: true,
   102→              assertionType: 'from_domain',
   103→              matchedValue: matchedDomain.domain,
   104→              confidence: 'HIGH_CONFIDENCE',
   105→              sourceGroup: source_group,
   106→              reason: `Email from domain '${emailDomain}' matches high-confidence domain '${matchedDomain.domain}' in group '${source_group}'`,
   107→            });
   108→            categoryHadAssertion = true;
   109→          }
   110→        }
   111→      }
   112→    }
   113→
   114→    // Check subject_prefixes
   115→    if (hardAssertions.subject_prefixes) {
   116→      const subject = email.subject.toLowerCase();
   117→
   118→      for (const prefix of hardAssertions.subject_prefixes) {
   119→        if (subject.startsWith(prefix.toLowerCase())) {
