import { z } from 'zod';
import { EmailMessage, HardAssertionResult } from '../types';

/**
 * Hard Assertions Stage
 *
 * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md "Hard Assertions" section.
 * Single match can directly elevate a top-level category to high confidence baseline.
 *
 * Logic:
 * - If any hard assertion matches: category_score = max(category_score, HIGH_CONFIDENCE_FLOOR)
 * - Mark flag: hard_assertion = true
 * - Where HIGH_CONFIDENCE_FLOOR = confidence_thresholds.high_confidence
 */

export interface ClassificationContext {
  emailId: string;
  sessionId: string;
  categoryScores: Record<string, number>;
  hardAssertionsApplied: string[];
  stageTimings: Record<string, number>;
  configurationRefs: Record<string, string>;
}

export interface HardAssertionConfig {
  from_domains_ref?: {
    source_group: string;
    confidence: 'high' | 'medium';
  };
  subject_prefixes?: string[];
  from_addresses?: string[];
}

export interface HardAssertionStageConfig {
  confidenceThresholds: {
    high_confidence: number;
    medium_confidence: number;
    low_confidence: number;
  };
  categorySignals: Record<string, { hard_assertions?: HardAssertionConfig }>;
  domainLookup: Record<
    string,
    {
      high_confidence: Array<{ domain: string; type?: string }>;
      medium_confidence: Array<{ domain: string; type?: string }>;
      low_confidence: Array<{ domain: string; type?: string }>;
    }
  >;
}

export interface HardAssertionStageResult {
  categoriesWithHardAssertions: string[];
  assertionResults: HardAssertionResult[];
  updatedScores: Record<string, number>;
  processingDurationMs: number;
}

/**
 * Executes hard assertions stage of email classification
 *
 * @param email The email message to classify
 * @param context Current classification context with category scores
 * @param config Configuration containing category signals and thresholds
 * @returns Hard assertion results and updated scores
 */
export function executeHardAssertions(
  email: EmailMessage,
  context: ClassificationContext,
  config: HardAssertionStageConfig
): HardAssertionStageResult {
  const startTime = Date.now();
  const categoriesWithHardAssertions: string[] = [];
  const assertionResults: HardAssertionResult[] = [];
  const updatedScores: Record<string, number> = { ...context.categoryScores };

  const HIGH_CONFIDENCE_FLOOR = config.confidenceThresholds.high_confidence;

  // Process each category that has hard assertions configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.hard_assertions) {
      continue;
    }

    const hardAssertions = categoryConfig.hard_assertions;
    let categoryHadAssertion = false;

    // Check from_domains_ref (domain-based hard assertions)
    if (hardAssertions.from_domains_ref) {
      const { source_group, confidence } = hardAssertions.from_domains_ref;

      // Only treat as hard assertion if confidence is 'high'
      if (confidence === 'high') {
        const domainGroup = config.domainLookup[source_group];
        if (domainGroup) {
          const emailDomain = extractDomainFromEmail(email.from.email);
          const matchedDomain = domainGroup.high_confidence.find((d) => domainMatches(emailDomain, d.domain));

          if (matchedDomain) {
            assertionResults.push({
              category: categoryName,
              triggered: true,
              assertionType: 'from_domain',
              matchedValue: matchedDomain.domain,
              confidence: 'HIGH_CONFIDENCE',
              sourceGroup: source_group,
              reason: `Email from domain '${emailDomain}' matches high-confidence domain '${matchedDomain.domain}' in group '${source_group}'`,
            });
            categoryHadAssertion = true;
          }
        }
      }
    }

    // Check subject_prefixes
    if (hardAssertions.subject_prefixes) {
      const subject = email.subject.toLowerCase();

      for (const prefix of hardAssertions.subject_prefixes) {
        if (subject.startsWith(prefix.toLowerCase())) {
          assertionResults.push({
            category: categoryName,
            triggered: true,
            assertionType: 'subject_prefix',
            matchedValue: prefix,
            confidence: 'HIGH_CONFIDENCE',
            reason: `Subject '${email.subject}' starts with hard assertion prefix '${prefix}'`,
          });
          categoryHadAssertion = true;
          break; // First match is sufficient
        }
      }
    }

    // Check from_addresses (exact email address matches)
    if (hardAssertions.from_addresses) {
      const fromEmail = email.from.email.toLowerCase();

      for (const address of hardAssertions.from_addresses) {
        if (fromEmail === address.toLowerCase()) {
          assertionResults.push({
            category: categoryName,
            triggered: true,
            assertionType: 'from_address',
            matchedValue: address,
            confidence: 'HIGH_CONFIDENCE',
            reason: `Email from address '${fromEmail}' matches hard assertion address '${address}'`,
          });
          categoryHadAssertion = true;
          break; // First match is sufficient
        }
      }
    }

    // Apply hard assertion score if any assertion matched
    if (categoryHadAssertion) {
      const currentScore = updatedScores[categoryName] || 0;
      const newScore = Math.max(currentScore, HIGH_CONFIDENCE_FLOOR);
      updatedScores[categoryName] = newScore;
      categoriesWithHardAssertions.push(categoryName);
    }
  }

  const processingDurationMs = Date.now() - startTime;

  // Update context tracking
  context.stageTimings['hard_assertions'] = processingDurationMs;
  context.configurationRefs['hard_assertions'] = 'category_signals.*.hard_assertions';
  context.hardAssertionsApplied = categoriesWithHardAssertions;

  return {
    categoriesWithHardAssertions,
    assertionResults,
    updatedScores,
    processingDurationMs,
  };
}

/**
 * Extract domain from email address
 * @param email Email address
 * @returns Domain portion (everything after @)
 */
function extractDomainFromEmail(email: string): string {
  const atIndex = email.lastIndexOf('@');
  if (atIndex === -1) {
    return email; // Invalid email, return as-is
  }
  return email.substring(atIndex + 1).toLowerCase();
}

/**
 * Check if email domain matches configured domain
 * Supports exact matches and subdomain matching
 *
 * @param emailDomain Domain from email address
 * @param configDomain Domain from configuration
 * @returns True if domains match
 */
function domainMatches(emailDomain: string, configDomain: string): boolean {
  const emailDomainLower = emailDomain.toLowerCase();
  const configDomainLower = configDomain.toLowerCase();

  // Exact match
  if (emailDomainLower === configDomainLower) {
    return true;
  }

  // Subdomain match (e.g., noreply.chase.com matches chase.com)
  if (emailDomainLower.endsWith('.' + configDomainLower)) {
    return true;
  }

  return false;
}

/**
 * Zod schema for validating hard assertion configuration
 */
export const HardAssertionConfigSchema = z
  .object({
    from_domains_ref: z
      .object({
        source_group: z.string(),
        confidence: z.enum(['high', 'medium']),
      })
      .optional(),
    subject_prefixes: z.array(z.string()).optional(),
    from_addresses: z.array(z.string().email()).optional(),
  })
  .refine(
    (config) => {
      // At least one assertion type must be configured
      return !!(config.from_domains_ref || config.subject_prefixes || config.from_addresses);
    },
    {
      message: 'At least one hard assertion type must be configured',
    }
  );

export const HardAssertionStageConfigSchema = z.object({
  confidenceThresholds: z.object({
    high_confidence: z.number().min(0),
    medium_confidence: z.number().min(0),
    low_confidence: z.number().min(0),
  }),
  categorySignals: z.record(
    z.object({
      hard_assertions: HardAssertionConfigSchema.optional(),
    })
  ),
  domainLookup: z.record(
    z.object({
      high_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      medium_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      low_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
    })
  ),
});

