import { z } from 'zod';
import { EmailMessage, StrongIndicatorResult } from '../types';
import {
  extractDomainFromEmail,
  findMatchingDomain,
  findMatchingKeywords,
  extractTextFromHtml,
} from '../utils/email-utils';

/**
 * Strong Indicators Stage
 *
 * Implements diminishing returns seeding per SCORING_LOGIC.md "Strong Indicator Seeding" section.
 * High-weight signals that provide strong category hints, applied with diminishing returns
 * across multiple dimensions (subject, from_domain, body).
 *
 * Logic:
 * - seed = Σ weighted_matches
 * - Diminishing returns per dimension: first full, rest * 0.5
 * - strong_indicator_seed = max(existing_seed, seed)
 * - Applied after hard assertions before subtype accumulation
 */

export interface ClassificationContext {
  emailId: string;
  sessionId: string;
  categoryScores: Record<string, number>;
  hardAssertionsApplied: string[];
  strongIndicatorSeeds: Record<string, number>;
  stageTimings: Record<string, number>;
  configurationRefs: Record<string, string>;
}

export interface StrongIndicatorConfig {
  from_domains_ref?: {
    source_group: string;
    confidence: 'high' | 'medium';
  };
  subject_contains?: string[];
  body_contains?: string[];
}

export interface StrongIndicatorStageConfig {
  confidenceThresholds: {
    high_confidence: number;
    medium_confidence: number;
    low_confidence: number;
  };
  categorySignals: Record<string, { strong_indicators?: StrongIndicatorConfig }>;
  domainLookup: Record<
    string,
    {
      high_confidence: Array<{ domain: string; type?: string }>;
      medium_confidence: Array<{ domain: string; type?: string }>;
      low_confidence: Array<{ domain: string; type?: string }>;
    }
  >;
  // Weight for strong indicators (typically 8-12 range for medium-high confidence)
  strongIndicatorBaseWeight: number;
  // Diminishing returns factor for subsequent matches in same dimension
  diminishingReturnsFactor: number;
}

export interface StrongIndicatorStageResult {
  categoriesWithStrongIndicators: string[];
  indicatorResults: StrongIndicatorResult[];
  updatedSeeds: Record<string, number>;
  processingDurationMs: number;
}

/**
 * Executes strong indicators stage of email classification
 *
 * @param email The email message to classify
 * @param context Current classification context with category scores and seeds
 * @param config Configuration containing category signals and thresholds
 * @returns Strong indicator results and updated seed scores
 */
export function executeStrongIndicators(
  email: EmailMessage,
  context: ClassificationContext,
  config: StrongIndicatorStageConfig
): StrongIndicatorStageResult {
  const startTime = Date.now();
  const categoriesWithStrongIndicators: string[] = [];
  const indicatorResults: StrongIndicatorResult[] = [];
  const updatedSeeds: Record<string, number> = { ...context.strongIndicatorSeeds };

  const baseWeight = config.strongIndicatorBaseWeight;
  const diminishingFactor = config.diminishingReturnsFactor;

  // Process each category that has strong indicators configured
  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    if (!categoryConfig.strong_indicators) {
      continue;
    }

    const strongIndicators = categoryConfig.strong_indicators;
    const existingSeed = updatedSeeds[categoryName] || 0;
    let categoryHadIndicator = false;
    let newSeedScore = existingSeed;

    // Track matches per dimension for diminishing returns
    const dimensionMatches = {
      from_domain: 0,
      subject_contains: 0,
      body_contains: 0,
    };

    // Check from_domains_ref (domain-based strong indicators)
    if (strongIndicators.from_domains_ref) {
      const { source_group, confidence } = strongIndicators.from_domains_ref;

      const domainGroup = config.domainLookup[source_group];
      if (domainGroup) {
        const emailDomain = extractDomainFromEmail(email.from.email);
        const matchedDomain = findMatchingDomain(emailDomain, domainGroup, confidence);

        if (matchedDomain) {
          dimensionMatches.from_domain++;
          const isFirstMatch = dimensionMatches.from_domain === 1;
          const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
          const proposedSeed = newSeedScore + effectiveWeight;

          indicatorResults.push({
            category: categoryName,
            indicatorType: 'from_domain',
            matchedValue: matchedDomain.domain,
            seedScore: effectiveWeight,
            diminishingReturnsApplied: !isFirstMatch,
            existingSeedScore: newSeedScore,
            finalSeedScore: proposedSeed,
            reason: `Email from domain '${emailDomain}' matches ${confidence}-confidence domain '${matchedDomain.domain}' in group '${source_group}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
          });

          newSeedScore = Math.max(newSeedScore, proposedSeed);
          categoryHadIndicator = true;
        }
      }
    }

    // Check subject_contains
    if (strongIndicators.subject_contains && email.subject) {
      const matchedKeywords = findMatchingKeywords(email.subject, strongIndicators.subject_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.subject_contains++;
        const isFirstMatch = dimensionMatches.subject_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'subject_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Subject '${email.subject}' contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Check body_contains
    if (strongIndicators.body_contains && (email.bodyPlain || email.bodyHtml)) {
      // Use plain text body if available, otherwise extract from HTML
      const bodyText = email.bodyPlain || extractTextFromHtml(email.bodyHtml || '');
      const matchedKeywords = findMatchingKeywords(bodyText, strongIndicators.body_contains);

      for (const keyword of matchedKeywords) {
        dimensionMatches.body_contains++;
        const isFirstMatch = dimensionMatches.body_contains === 1;
        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
        const proposedSeed = newSeedScore + effectiveWeight;

        indicatorResults.push({
          category: categoryName,
          indicatorType: 'body_contains',
          matchedValue: keyword,
          seedScore: effectiveWeight,
          diminishingReturnsApplied: !isFirstMatch,
          existingSeedScore: newSeedScore,
          finalSeedScore: proposedSeed,
          reason: `Body text contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
        });

        newSeedScore = Math.max(newSeedScore, proposedSeed);
        categoryHadIndicator = true;
      }
    }

    // Update seed score using max logic (strong_indicator_seed = max(existing_seed, seed))
    if (categoryHadIndicator) {
      updatedSeeds[categoryName] = newSeedScore;
      categoriesWithStrongIndicators.push(categoryName);
    }
  }

  const processingDurationMs = Date.now() - startTime;

  // Update context tracking
  context.stageTimings['strong_indicators'] = processingDurationMs;
  context.configurationRefs['strong_indicators'] = 'category_signals.*.strong_indicators';
  context.strongIndicatorSeeds = updatedSeeds;

  return {
    categoriesWithStrongIndicators,
    indicatorResults,
    updatedSeeds,
    processingDurationMs,
  };
}

/**
 * Zod schema for validating strong indicator configuration
 */
export const StrongIndicatorConfigSchema = z
  .object({
    from_domains_ref: z
      .object({
        source_group: z.string(),
        confidence: z.enum(['high', 'medium']),
      })
      .optional(),
    subject_contains: z.array(z.string()).optional(),
    body_contains: z.array(z.string()).optional(),
  })
  .refine(
    (config) => {
      // At least one indicator type must be configured
      return !!(config.from_domains_ref || config.subject_contains || config.body_contains);
    },
    {
      message: 'At least one strong indicator type must be configured',
    }
  );

export const StrongIndicatorStageConfigSchema = z.object({
  confidenceThresholds: z.object({
    high_confidence: z.number().min(0),
    medium_confidence: z.number().min(0),
    low_confidence: z.number().min(0),
  }),
  categorySignals: z.record(
    z.object({
      strong_indicators: StrongIndicatorConfigSchema.optional(),
    })
  ),
  domainLookup: z.record(
    z.object({
      high_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      medium_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
      low_confidence: z.array(
        z.object({
          domain: z.string(),
          type: z.string().optional(),
        })
      ),
    })
  ),
  strongIndicatorBaseWeight: z.number().min(0).default(10), // Typical range 8-12
  diminishingReturnsFactor: z.number().min(0).max(1).default(0.5), // First full, rest * 0.5
});

